/**
 * Advanced Example Module Types
 *
 * Comprehensive type definitions demonstrating E-Menum module type patterns.
 * This file showcases:
 * - Entity types (base + with relations)
 * - Request/Response DTOs
 * - Query parameter types
 * - Event payload types
 * - Hook context types
 * - Module settings types
 *
 * @module modules/_examples/advanced-example/types
 *
 * @example
 * ```typescript
 * import type {
 *   AdvancedExample,
 *   CreateExampleRequest,
 *   ExampleWithRelations,
 * } from '@/modules/_examples/advanced-example/advanced-example.types';
 *
 * async function createExample(data: CreateExampleRequest): Promise<AdvancedExample> {
 *   // Implementation
 * }
 * ```
 */

// -----------------------------------------------------------------------------
// Enums
// -----------------------------------------------------------------------------

/**
 * Example status enum
 */
export enum ExampleStatus {
  /** Draft - not yet published */
  DRAFT = 'DRAFT',
  /** Pending - awaiting approval */
  PENDING = 'PENDING',
  /** Active - published and visible */
  ACTIVE = 'ACTIVE',
  /** Inactive - temporarily disabled */
  INACTIVE = 'INACTIVE',
  /** Archived - no longer active */
  ARCHIVED = 'ARCHIVED',
}

/**
 * Example priority enum
 */
export enum ExamplePriority {
  LOW = 'LOW',
  MEDIUM = 'MEDIUM',
  HIGH = 'HIGH',
  URGENT = 'URGENT',
}

/**
 * Example type enum
 */
export enum ExampleType {
  STANDARD = 'STANDARD',
  PREMIUM = 'PREMIUM',
  CUSTOM = 'CUSTOM',
}

// -----------------------------------------------------------------------------
// Settings Types
// -----------------------------------------------------------------------------

/**
 * Example item settings JSON structure
 */
export interface ExampleSettings {
  /** Enable notifications */
  notificationsEnabled?: boolean;
  /** Custom theme color */
  themeColor?: string;
  /** Maximum allowed items */
  maxItems?: number;
  /** Feature flags */
  features?: Record<string, boolean>;
  /** Custom metadata */
  metadata?: Record<string, unknown>;
}

/**
 * Example module settings
 */
export interface AdvancedExampleModuleSettings {
  /** Maximum items per page */
  maxItemsPerPage: number;
  /** Enable processing feature */
  enableProcessing: boolean;
  /** Processing timeout in milliseconds */
  processingTimeout: number;
  /** Notify on create */
  notifyOnCreate: boolean;
  /** Log level */
  logLevel: 'debug' | 'info' | 'warn' | 'error';
}

// -----------------------------------------------------------------------------
// Base Entity Types
// -----------------------------------------------------------------------------

/**
 * Advanced Example entity
 *
 * This demonstrates a standard E-Menum entity with:
 * - CUID primary key
 * - organizationId for multi-tenancy
 * - Status field with enum
 * - JSON settings field
 * - Timestamps (createdAt, updatedAt, deletedAt)
 */
export interface AdvancedExample {
  /** Unique identifier (CUID) */
  id: string;
  /** Organization ID (tenant) - CRITICAL for multi-tenancy */
  organizationId: string;
  /** Branch ID (optional) */
  branchId: string | null;
  /** Example name */
  name: string;
  /** URL-friendly slug */
  slug: string;
  /** Description */
  description: string | null;
  /** Example type */
  type: ExampleType;
  /** Current status */
  status: ExampleStatus;
  /** Priority level */
  priority: ExamplePriority;
  /** Example settings (JSON) */
  settings: ExampleSettings;
  /** Tags for filtering */
  tags: string[];
  /** Sort order */
  sortOrder: number;
  /** Processed flag */
  isProcessed: boolean;
  /** Featured flag */
  isFeatured: boolean;
  /** Created by user ID */
  createdBy: string | null;
  /** Updated by user ID */
  updatedBy: string | null;
  /** Creation timestamp */
  createdAt: Date;
  /** Last update timestamp */
  updatedAt: Date;
  /** Soft delete timestamp */
  deletedAt: Date | null;
}

/**
 * Example item (child entity)
 *
 * Demonstrates a related entity pattern
 */
export interface ExampleItem {
  /** Item ID */
  id: string;
  /** Parent example ID */
  exampleId: string;
  /** Item name */
  name: string;
  /** Item value */
  value: string | number;
  /** Item order */
  sortOrder: number;
  /** Active status */
  isActive: boolean;
  /** Creation timestamp */
  createdAt: Date;
  /** Last update timestamp */
  updatedAt: Date;
}

/**
 * Advanced Example with relations
 */
export interface AdvancedExampleWithRelations extends AdvancedExample {
  /** Related items */
  items?: ExampleItem[];
  /** Created by user */
  creator?: {
    id: string;
    name: string;
    email: string;
  };
  /** Organization info */
  organization?: {
    id: string;
    name: string;
    slug: string;
  };
  /** Item count */
  itemCount?: number;
}

// -----------------------------------------------------------------------------
// Request Types
// -----------------------------------------------------------------------------

/**
 * Create example request
 *
 * Demonstrates request DTO pattern with:
 * - Required fields
 * - Optional fields with defaults
 * - Nested object fields
 */
export interface CreateExampleRequest {
  /** Example name (required) */
  name: string;
  /** URL-friendly slug (auto-generated if not provided) */
  slug?: string;
  /** Description */
  description?: string;
  /** Example type */
  type?: ExampleType;
  /** Initial status */
  status?: ExampleStatus;
  /** Priority level */
  priority?: ExamplePriority;
  /** Branch ID (optional) */
  branchId?: string;
  /** Example settings */
  settings?: ExampleSettings;
  /** Tags */
  tags?: string[];
  /** Sort order */
  sortOrder?: number;
  /** Featured flag */
  isFeatured?: boolean;
  /** Initial items to create */
  items?: CreateExampleItemRequest[];
}

/**
 * Update example request
 *
 * Demonstrates partial update pattern - all fields optional
 */
export interface UpdateExampleRequest {
  /** Example name */
  name?: string;
  /** URL-friendly slug */
  slug?: string;
  /** Description */
  description?: string | null;
  /** Example type */
  type?: ExampleType;
  /** Status */
  status?: ExampleStatus;
  /** Priority level */
  priority?: ExamplePriority;
  /** Branch ID */
  branchId?: string | null;
  /** Example settings (merged with existing) */
  settings?: ExampleSettings;
  /** Tags */
  tags?: string[];
  /** Sort order */
  sortOrder?: number;
  /** Featured flag */
  isFeatured?: boolean;
}

/**
 * Create example item request
 */
export interface CreateExampleItemRequest {
  /** Item name */
  name: string;
  /** Item value */
  value: string | number;
  /** Sort order */
  sortOrder?: number;
  /** Active status */
  isActive?: boolean;
}

/**
 * Update example item request
 */
export interface UpdateExampleItemRequest {
  /** Item name */
  name?: string;
  /** Item value */
  value?: string | number;
  /** Sort order */
  sortOrder?: number;
  /** Active status */
  isActive?: boolean;
}

/**
 * Change status request
 */
export interface ChangeStatusRequest {
  /** New status */
  status: ExampleStatus;
  /** Reason for status change */
  reason?: string;
}

/**
 * Process example request
 */
export interface ProcessExampleRequest {
  /** Processing options */
  options?: {
    /** Async processing */
    async?: boolean;
    /** Notification on complete */
    notifyOnComplete?: boolean;
    /** Custom processor */
    processor?: string;
  };
}

/**
 * Bulk operation request
 */
export interface BulkOperationRequest {
  /** IDs to operate on */
  ids: string[];
  /** Operation type */
  operation: 'delete' | 'archive' | 'activate' | 'deactivate';
  /** Additional options */
  options?: Record<string, unknown>;
}

// -----------------------------------------------------------------------------
// Query Types
// -----------------------------------------------------------------------------

/**
 * List examples query parameters
 *
 * Demonstrates comprehensive query pattern with:
 * - Pagination (page, perPage)
 * - Sorting (sortBy, sortOrder)
 * - Filtering (status, type, etc.)
 * - Search
 * - Include relations
 */
export interface ListExamplesQuery {
  /** Filter by status */
  status?: ExampleStatus;
  /** Filter by type */
  type?: ExampleType;
  /** Filter by priority */
  priority?: ExamplePriority;
  /** Filter by branch ID */
  branchId?: string;
  /** Filter by featured */
  isFeatured?: boolean;
  /** Filter by processed */
  isProcessed?: boolean;
  /** Filter by tags (any match) */
  tags?: string[];
  /** Search by name/description */
  search?: string;
  /** Include relations */
  include?: Array<'items' | 'creator' | 'organization'>;
  /** Page number */
  page?: number;
  /** Items per page */
  perPage?: number;
  /** Sort field */
  sortBy?: 'name' | 'createdAt' | 'updatedAt' | 'sortOrder' | 'priority';
  /** Sort direction */
  sortOrder?: 'asc' | 'desc';
  /** Created after date */
  createdAfter?: Date;
  /** Created before date */
  createdBefore?: Date;
}

/**
 * List items query parameters
 */
export interface ListExampleItemsQuery {
  /** Filter by active status */
  isActive?: boolean;
  /** Search by name */
  search?: string;
  /** Page number */
  page?: number;
  /** Items per page */
  perPage?: number;
}

// -----------------------------------------------------------------------------
// Response Types
// -----------------------------------------------------------------------------

/**
 * Paginated result type
 */
export interface PaginatedResult<T> {
  /** Data array */
  data: T[];
  /** Pagination metadata */
  meta: {
    page: number;
    perPage: number;
    total: number;
    totalPages: number;
  };
}

/**
 * Example summary (for lists/dropdowns)
 */
export interface ExampleSummary {
  /** Example ID */
  id: string;
  /** Example name */
  name: string;
  /** Example slug */
  slug: string;
  /** Status */
  status: ExampleStatus;
  /** Item count */
  itemCount: number;
  /** Created at */
  createdAt: Date;
}

/**
 * Example statistics
 */
export interface ExampleStatistics {
  /** Total count */
  total: number;
  /** Count by status */
  byStatus: Record<ExampleStatus, number>;
  /** Count by type */
  byType: Record<ExampleType, number>;
  /** Featured count */
  featured: number;
  /** Processed count */
  processed: number;
  /** Recent activity (last 7 days) */
  recentActivity: {
    created: number;
    updated: number;
    deleted: number;
  };
}

// -----------------------------------------------------------------------------
// Event Payload Types
// -----------------------------------------------------------------------------

/**
 * Base event payload
 */
export interface BaseEventPayload {
  /** Organization ID */
  organizationId: string;
  /** Event timestamp */
  timestamp: string;
  /** User who triggered the event */
  triggeredBy?: string;
}

/**
 * Example created event payload
 */
export interface ExampleCreatedEventPayload extends BaseEventPayload {
  /** Example ID */
  exampleId: string;
  /** Example name */
  name: string;
  /** Initial status */
  status: ExampleStatus;
}

/**
 * Example updated event payload
 */
export interface ExampleUpdatedEventPayload extends BaseEventPayload {
  /** Example ID */
  exampleId: string;
  /** Changed fields */
  changes: Record<string, unknown>;
}

/**
 * Example deleted event payload
 */
export interface ExampleDeletedEventPayload extends BaseEventPayload {
  /** Example ID */
  exampleId: string;
  /** Example name */
  name: string;
}

/**
 * Example status changed event payload
 */
export interface ExampleStatusChangedEventPayload extends BaseEventPayload {
  /** Example ID */
  exampleId: string;
  /** Previous status */
  previousStatus: ExampleStatus;
  /** New status */
  newStatus: ExampleStatus;
  /** Reason for change */
  reason?: string;
}

/**
 * Example processed event payload
 */
export interface ExampleProcessedEventPayload extends BaseEventPayload {
  /** Example ID */
  exampleId: string;
  /** Processing result */
  result: 'success' | 'failure';
  /** Processing duration in ms */
  duration: number;
  /** Error message if failed */
  error?: string;
}

// -----------------------------------------------------------------------------
// Hook Context Types
// -----------------------------------------------------------------------------

/**
 * Before create hook context
 */
export interface BeforeCreateContext {
  /** Create request data */
  data: CreateExampleRequest;
  /** Organization ID */
  organizationId: string;
  /** User ID */
  userId?: string;
}

/**
 * After create hook context
 */
export interface AfterCreateContext {
  /** Created example */
  example: AdvancedExample;
  /** Organization ID */
  organizationId: string;
  /** User ID */
  userId?: string;
}

/**
 * Before update hook context
 */
export interface BeforeUpdateContext {
  /** Example being updated */
  example: AdvancedExample;
  /** Update request data */
  data: UpdateExampleRequest;
  /** Organization ID */
  organizationId: string;
  /** User ID */
  userId?: string;
}

/**
 * After update hook context
 */
export interface AfterUpdateContext {
  /** Updated example */
  example: AdvancedExample;
  /** Changes made */
  changes: Record<string, unknown>;
  /** Organization ID */
  organizationId: string;
  /** User ID */
  userId?: string;
}

/**
 * Before delete hook context
 */
export interface BeforeDeleteContext {
  /** Example being deleted */
  example: AdvancedExample;
  /** Organization ID */
  organizationId: string;
  /** User ID */
  userId?: string;
}

/**
 * After delete hook context
 */
export interface AfterDeleteContext {
  /** Deleted example */
  example: AdvancedExample;
  /** Organization ID */
  organizationId: string;
  /** User ID */
  userId?: string;
}

/**
 * Process hook context
 */
export interface ProcessContext {
  /** Example being processed */
  example: AdvancedExample;
  /** Processing options */
  options: ProcessExampleRequest['options'];
  /** Organization ID */
  organizationId: string;
  /** User ID */
  userId?: string;
}
